import{_ as a,o as i,c as t,a6 as n}from"./chunks/framework.DtxWasON.js";const u=JSON.parse('{"title":"Light Client/REST","description":"","frontmatter":{},"headers":[],"relativePath":"mainchain/software/light-client-rpc.md","filePath":"mainchain/software/light-client-rpc.md"}'),s={name:"mainchain/software/light-client-rpc.md"};function o(l,e,r,h,c,d){return i(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="light-client-rest" tabindex="-1">Light Client/REST <a class="header-anchor" href="#light-client-rest" aria-label="Permalink to &quot;Light Client/REST&quot;">​</a></h1><p>The <code>und</code> binary comes packaged with a full REST capable server, from which the majority of the <code>und query ...</code> and <code>und tx ...</code> commands can also be served.</p><p>The REST server is generally useful for third party services such as <a href="https://github.com/unification-com/web-wallet" target="_blank" rel="noreferrer">wallets</a> and <a href="https://github.com/unification-com/mainchain-explorer" target="_blank" rel="noreferrer">block explorers</a>. It interacts with, and can be used alongside the <code>und</code> RPC interface.</p><h4 id="contents" tabindex="-1">Contents <a class="header-anchor" href="#contents" aria-label="Permalink to &quot;Contents&quot;">​</a></h4><nav class="table-of-contents"><ul><li><a href="#prerequisites">Prerequisites</a></li><li><a href="#running-a-light-client">Running a light client</a></li><li><a href="#running-an-archive-rpc-node">Running an Archive RPC node</a></li></ul></nav><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before continuing, ensure you have gone through the following docs:</p><ol><li><a href="./../software/cosmovisor/install_und_with_cosmovisor.html">Install und with Cosmovisor</a></li></ol><h2 id="running-a-light-client" tabindex="-1">Running a light client <a class="header-anchor" href="#running-a-light-client" aria-label="Permalink to &quot;Running a light client&quot;">​</a></h2><p>The Light Client can be started by setting the configuring options for a full node in <code>app.toml</code> as follows:</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">api</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">enable = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">swagger = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">address = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tcp://0.0.0.0:1317&quot;</span></span></code></pre></div><p>Then running the <code>und start</code> command as normal</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span></code></pre></div><p>This will start the light client on your local host listening on <code>localhost:1317</code>, and use the node hosted at <code>11.22.33.44:26657</code> to source its data and interface with the <code>FUND-Mainchain-TestNet-v8</code> chain (e.g. broadcast any transactions).</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>setting the listen address IP to <code>0.0.0.0</code>, e.g. <code>tcp://0.0.0.0:1317</code> will allow any host to connect to your REST server.</p></div><p>Once running, you can visit <a href="http://localhost:1317/swagger/" target="_blank" rel="noreferrer">http://localhost:1317/swagger/</a> to view all the REST endpoints available.</p><h2 id="running-an-archive-rpc-node" tabindex="-1">Running an Archive RPC node <a class="header-anchor" href="#running-an-archive-rpc-node" aria-label="Permalink to &quot;Running an Archive RPC node&quot;">​</a></h2><p>Light Clients are more effective when interfacing with full nodes running in &quot;archive&quot; mode. Nodes running in archive mode do not prune any sync data, and keep a complete transaction event history.</p><p>The quickest way to get up and running with an archive node is to configure the pruning option in <code>$HOME/.und_mainchain/config/app.toml</code>:</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pruning = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;nothing&quot;</span></span></code></pre></div><p>Then, start the full node as usual using:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span></code></pre></div><p>Your light client can then be configured to connect to it via the <code>--node</code> flag by passing <code>tcp://127.0.0.1:26657</code> to it.</p>`,23)])])}const g=a(s,[["render",o]]);export{u as __pageData,g as default};
